# [XAML](#tab/tabid-1)

<map:SfMaps>
    <map:SfMaps.Layer>
        <map:MapShapeLayer x:Name="layer"
                           ShapesSource="https://cdn.syncfusion.com/maps/map-data/world-map.json"
                           ShowMarkerTooltip="True">

            <map:MapShapeLayer.Markers>
                <map:MapMarkerCollection>
                    <map:MapMarker x:Name="Seattle"
                                   Latitude="47.60621"
                                   Longitude="-122.332071" />
                    <map:MapMarker x:Name="Belem"
                                   Latitude="-1.455833"
                                   Longitude="-48.503887" />
                </map:MapMarkerCollection>
            </map:MapShapeLayer.Markers>

            <map:MapShapeLayer.MarkerTooltipTemplate>
                <DataTemplate>
                    <Grid Background="{TemplateBinding Background}">
                        <Grid.RowDefinitions>
                            <RowDefinition Height="Auto" />
                            <RowDefinition Height="Auto" />
                            <RowDefinition Height="Auto" />
                        </Grid.RowDefinitions>

                        <Grid.ColumnDefinitions>
                            <ColumnDefinition />
                            <ColumnDefinition />
                        </Grid.ColumnDefinitions>

                        <Label Text="Latitude: "
                               TextColor="{Binding TextStyle.TextColor}" />
                        <Label Grid.Column="1"
                               Margin="5,0,0,0"
                               HorizontalTextAlignment="End"
                               Text="{Binding DataItem.Latitude}"
                               TextColor="{Binding TextStyle.TextColor}" />

                        <BoxView Grid.Row="1"
                                 Grid.ColumnSpan="2"
                                 HeightRequest="1"
                                 BackgroundColor="Red" />

                        <Label Grid.Row="3"
                               Text="Longitude: "
                               TextColor="{Binding TextStyle.TextColor}" />
                        <Label Grid.Row="3"
                               Grid.Column="1"
                               Margin="5,0,0,0"
                               HorizontalTextAlignment="End"
                               Text="{Binding DataItem.Longitude}"
                               TextColor="{Binding TextStyle.TextColor}" />

                    </Grid>
                </DataTemplate>
            </map:MapShapeLayer.MarkerTooltipTemplate>

            <map:MapShapeLayer.MarkerTooltipSettings>
                <map:MapTooltipSettings Background="White"
                                        Padding="2">
                    <map:MapTooltipSettings.TextStyle>
                        <map:MapLabelStyle FontSize="12"
                                           TextColor="Black"
                                           FontAttributes="Italic" />
                    </map:MapTooltipSettings.TextStyle>
                </map:MapTooltipSettings>
            </map:MapShapeLayer.MarkerTooltipSettings>
        </map:MapShapeLayer>
    </map:SfMaps.Layer>
</map:SfMaps>

# [C#](#tab/tabid-2)

