# [C#](#tab/tabid-2)

public partial class MapImageryLayer : MapTileLayer
{
  protected override string GetTileUrl(int x, int y, int z)
  {
       string url = base.GetTileUrl(x, y, z);
       ServerName = "Custom";
       return url;
   }
}

