       });
layer.ColorMappings.Add(new RangeColorMapping()
{
   Color = Colors.Blue,
           From = 201,
           To = 300,
           Text = "200 - 300/km"
       });
layer.ColorMappings.Add(new RangeColorMapping()
{
   Color = Colors.Orange,
           From = 301,
           To = 400,
           Text = "300 - 400/km"
       });
layer.ColorMappings.Add(new RangeColorMapping()
