             <map:RangeColorMapping Color="#002db3" From="1000" To="5000" Text="1000-5000" />
             <map:RangeColorMapping Color="#001a66" From="5000" To="50000" Text="5000-50000" />
         </map:MapShapeLayer.ColorMappings>

      </map:MapShapeLayer>
