 colorMapping3.Color = Color.FromRgb(0, 57, 230);
 colorMapping3.From = 500;
 colorMapping3.To = 1000;
 colorMapping3.Text = "500-1000";
 RangeColorMapping colorMapping4 = new RangeColorMapping();
