// Model.
public class CountryDensity
{
    public string CountryName { get; set; }
    public double Density { get; set; }

    public CountryDensity(string countryName, double density)
    {
        this.CountryName = countryName;
        this.Density = density;
    }
}

// View Model.
public class RangeViewModel
{
    public ObservableCollection<CountryDensity> PopulationDensity { get; set; }

    public RangeViewModel()
    {
        PopulationDensity = new ObservableCollection<CountryDensity>()
        {
           new CountryDensity("New South Wales", 19341),
           new CountryDensity("Queensland", 21055),
           new CountryDensity("Northern Territory", 8041),
           new CountryDensity("Western Australia", 6677),
           new CountryDensity("South Australia", 149)
           new CountryDensity("Victoria", 149)
        };
    }
}    


