<map:SfMaps>
    <map:SfMaps.Layer>
        <map:MapShapeLayer ShapesSource="https://cdn.syncfusion.com/maps/map-data/world-map.json">
            <map:MapShapeLayer.Sublayers>
                 <map:MapShapeSublayer ShapesSource="https://cdn.syncfusion.com/maps/map-data/australia.json"
                                       ShapeFill="LightGreen"
                                       ShapeStroke="Green"
                                       ShapeStrokeThickness="0.5"
                                       DataSource="{Binding PopulationDensity}"
                                       ShapeDataField="STATE_NAME"
                                       PrimaryValuePath="CountryName"
                                       ShapeColorValuePath="Density"
                                       ShowDataLabels="True"
                                       ShowBubbles="True"
                                       EnableSelection="True"
                                       SelectedShapeFill="Yellow"
                                       SelectedShapeStroke="Red"
                                       SelectedShapeStrokeThickness="2"
                                       ShapeHoverFill="DarkGray"
                                       ShapeHoverStroke="Yellow"
                                       ShapeHoverStrokeThickness="1"
                                       ShowShapeTooltip="True"
                                       ShowBubbleTooltip="True">

                    <map:MapShapeSublayer.ColorMappings>
                        <map:RangeColorMapping Color="#809fff" From="0" To="100" Text="0-100" />
                        <map:RangeColorMapping Color="#3366ff" From="100" To="500" Text="100-500" />
                        <map:RangeColorMapping Color="#0039e6" From="500" To="1000" Text="500-1000" />
                        <map:RangeColorMapping Color="#002db3" From="1000" To="5000" Text="1000-5000" />
                        <map:RangeColorMapping Color="#001a66" From="5000" To="50000" Text="5000-50000" />
                    </map:MapShapeSublayer.ColorMappings>

                    <map:MapShapeSublayer.DataLabelSettings>
                        <map:MapDataLabelSettings DataLabelPath="Density"/>
                    </map:MapShapeSublayer.DataLabelSettings>

                    <map:MapShapeSublayer.BubbleSettings>
                        <map:MapBubbleSettings SizeValuePath="Density" />
                    </map:MapShapeSublayer.BubbleSettings>

                    <map:MapShapeSublayer.BubbleTooltipSettings>
                        <map:MapTooltipSettings Background="White"
                                                Padding="2">
                            <map:MapTooltipSettings.TextStyle>
                                <map:MapLabelStyle FontSize="12"
                                                   TextColor="Black"
                                                   FontAttributes="Italic" />
                            </map:MapTooltipSettings.TextStyle>
                        </map:MapTooltipSettings>
                    </map:MapShapeSublayer.BubbleTooltipSettings>

                </map:MapShapeSublayer>
           </map:MapShapeLayer.Sublayers>
        </map:MapShapeLayer>
    </map:SfMaps.Layer>
</map:SfMaps>

# [C#](#tab/tabid-2)

SfMaps maps = new SfMaps();
MapShapeLayer layer = new MapShapeLayer();
RangeViewModel rangeViewModel = new RangeViewModel();
this.BindingContext = new RangeViewModel();
layer.ShapesSource = MapSource.FromUri(new Uri("https://cdn.syncfusion.com/maps/map-data/world-map.json"));
MapShapeSublayer sublayer = new MapShapeSublayer();
sublayer.ShapesSource = MapSource.FromUri(new Uri("https://cdn.syncfusion.com/maps/map-data/australia.json"));
sublayer.ShapeFill = Brush.LightGreen;
sublayer.ShapeStroke = Brush.Green;
sublayer.ShapeStrokeThickness = 0.5;
sublayer.DataSource = rangeViewModel.PopulationDensity;
sublayer.ShapeDataField = "STATE_NAME";
sublayer.PrimaryValuePath="CountryName";
sublayer.ShapeColorValuePath="Density";
sublayer.ShowDataLabels = true;
sublayer.ShowBubbles = true;
sublayer.EnableSelection = true;
sublayer.SelectedShapeFill=Colors.Yellow;
sublayer.SelectedShapeStroke = Colors.Red;
sublayer.SelectedShapeStrokeThickness = 2;
sublayer.ShapeHoverFill = Colors.DarkGray;
sublayer.ShapeHoverStroke = Colors.Yellow;
sublayer.ShapeHoverStrokeThickness = 4;
sublayer.ShowShapeTooltip = true;
sublayer.ShowBubbleTooltip = true;
RangeColorMapping colorMapping1 = new RangeColorMapping();
colorMapping1.Color =Color.FromRgb(128, 159, 255);
colorMapping1.From = 0;
colorMapping1.To = 100;
colorMapping1.Text = "0-100";
RangeColorMapping colorMapping2 = new RangeColorMapping();
colorMapping2.Color = Color.FromRgb(51, 102, 255);
colorMapping2.From = 100;
colorMapping2.To = 500;
colorMapping2.Text = "100-500";
RangeColorMapping colorMapping3 = new RangeColorMapping();
colorMapping3.Color = Color.FromRgb(0, 57, 230);
colorMapping3.From = 500;
colorMapping3.To = 1000;
colorMapping3.Text = "500-1000";
RangeColorMapping colorMapping4 = new RangeColorMapping();
colorMapping4.Color = Color.FromRgb(0, 45, 179);
colorMapping4.From = 1000;
colorMapping4.To = 5000;
colorMapping4.Text = "1000-5000";
RangeColorMapping colorMapping5 = new RangeColorMapping();
colorMapping5.Color = Color.FromRgb(0, 26, 102);
colorMapping5.From = 5000;
colorMapping5.To = 50000;
colorMapping5.Text = "5000-50000";
sublayer.ColorMappings.Add(colorMapping1);
sublayer.ColorMappings.Add(colorMapping2);
sublayer.ColorMappings.Add(colorMapping3);
sublayer.ColorMappings.Add(colorMapping4);
sublayer.ColorMappings.Add(colorMapping5);
sublayer.DataLabelSettings = new MapDataLabelSettings()
{
    DataLabelPath = "Density"
};
MapBubbleSettings bubbleSetting = new MapBubbleSettings()
{
   SizeValuePath = "Density"
};
sublayer.BubbleSettings = bubbleSetting;
sublayer.BubbleTooltipSettings = new MapTooltipSettings()
{
   Background = Colors.White,
   Padding = new Thickness(2),
   TextStyle = new MapLabelStyle()
   {
       FontSize = 12,
       TextColor = Colors.Black,
       FontAttributes = FontAttributes.Italic
   }
};
layer.Sublayers.Add(sublayer);
maps.Layer = layer;
this.Content = maps;

