                 <map:MapArcLayer>
                       <map:MapArcLayer.Arcs>
                            <map:MapArc>
                                <map:MapArc.From>
                                    <map:MapLatLng Latitude="26.841944"
                                                   Longitude="114.561183" />
                                </map:MapArc.From>
                                <map:MapArc.To>
                                   <map:MapLatLng Latitude="37.316207"
                                                  Longitude="89.494558" />
                                </map:MapArc.To>
                           </map:MapArc>

                            <map:MapArc>
                                <map:MapArc.From>
                                    <map:MapLatLng Latitude="5.562764"
                                                   Longitude="101.470795" />
                                </map:MapArc.From>
                                <map:MapArc.To>
                                   <map:MapLatLng Latitude="-19.138292"
                                                  Longitude="44.822302" />
                                </map:MapArc.To>
                           </map:MapArc>
                     </map:MapArcLayer.Arcs>
